"use client";

import { useEffect, useRef } from "react";
import type { CSSProperties } from "react";
import Cadence from "./Cadence";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/** The three-distance principle (三遠) of Guo Xi, 11th c. Each as a row. */
const DISTANCES = [
  {
    zh: "高遠",
    py: "gāo yuǎn",
    en: "high distance",
    note: "looking up at a peak — the mountain towers over you.",
    noteZh: "自山下而仰山巔 — 山勢巍然。",
  },
  {
    zh: "深遠",
    py: "shēn yuǎn",
    en: "deep distance",
    note: "looking past the near ridge into a hidden valley behind it.",
    noteZh: "自山前而窺山後 — 層巒深隱。",
  },
  {
    zh: "平遠",
    py: "píng yuǎn",
    en: "level distance",
    note: "looking across an even expanse, ridges dissolving into haze.",
    noteZh: "自近山而望遠山 — 漸入煙嵐。",
  },
];

/**
 * Section 02 — the scroll guide. A pinned scene (scroll-scrub-pinned) whose
 * inner layers part with parallax as you scroll: the three-distance principle
 * of Northern-Song literati painting (Guo Xi's Linquan Gaozhi), the hand-scroll
 * metaphor, and the depth principle this whole entry is built on — 远山如黛,
 * distance expressed as ink density, not perspective. The couplet reveals
 * glyph by glyph on the brush's cadence.
 *
 * `data-reveal="scene"` means the container hands `is-visible` to its
 * choreography but never animates itself.
 */
export default function ScrollGuide() {
  const artRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    const art = artRef.current;
    if (!art || reduced) return; // rests at --p: 0.5 under reduced motion

    // Drive the parallax layers' --p (0..1) from the section's progress
    // through the viewport: 0 when the stage enters at the bottom, 1 when it
    // leaves at the top. This is the scroll-scrub — the layers part like
    // depth as you read past the three-distance principle. The write is a
    // single custom property on one element; no layout, no re-render.
    let raf = 0;
    const update = () => {
      raf = 0;
      const rect = art.getBoundingClientRect();
      const vh = window.innerHeight;
      // progress: -rect.top ranges from ~vh (just entered) to ~-rect.height
      // (just left). Normalize to 0..1 across that travel.
      const travel = vh + rect.height;
      const p = Math.max(0, Math.min(1, (vh - rect.top) / travel));
      art.style.setProperty("--p", p.toFixed(3));
    };
    const onScroll = () => {
      if (!raf) raf = requestAnimationFrame(update);
    };
    update();
    window.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", onScroll, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onScroll);
      if (raf) cancelAnimationFrame(raf);
    };
  }, [reduced]);

  return (
    <section
      className="shan-guide"
      aria-labelledby="shan-guide-title"
      data-reveal="scene"
    >
      <div className="shan-guide__stage">
        {/* The pinned parallax layers — translateY driven by --p (0..1)
            which the scroll listener below writes from the section's
            viewport progress. */}
        <div className="shan-guide__art" ref={artRef} aria-hidden="true">
          <span className="shan-guide__layer shan-guide__layer--far">
            遠
          </span>
          <span className="shan-guide__layer shan-guide__layer--mid">
            山
          </span>
          <span className="shan-guide__layer shan-guide__layer--near">
            如
          </span>
          <span className="shan-guide__layer shan-guide__layer--fg">
            黛
          </span>
        </div>

        <div className="shan-guide__copy">
          <p className="shan-eyebrow" aria-hidden="true">
            02 — 三遠 · the three distances
          </p>
          <h2 className="shan-guide__title" id="shan-guide-title">
            Distant mountains are like eyebrow pigment.{" "}
            <span lang="zh" className="shan-guide__titlezh">
              遠山如黛
            </span>
          </h2>
          <p className="shan-guide__lede">
            In a Chinese landscape, distance is not measured in paces. It is
            measured in ink — the farther a ridge, the paler it washes, until
            the horizon is almost the paper itself.{" "}
            <span lang="zh" className="shan-guide__ledezh">
              山水之中，遠近不以步量，以墨濃淡。山愈遠，色愈淡，至天際幾近於紙。
            </span>
          </p>

          <ol className="shan-guide__distances">
            {DISTANCES.map((d, i) => (
              <li
                key={d.zh}
                className="shan-guide__row"
                style={{ "--kd": `${i * 110}ms` } as CSSProperties}
              >
                <span className="shan-guide__zh" lang="zh">
                  {d.zh}
                </span>
                <span className="shan-guide__py">{d.py}</span>
                <span className="shan-guide__en">“{d.en}”</span>
                <span className="shan-guide__note">
                  {d.note}{" "}
                  <span lang="zh" className="shan-guide__notezh">
                    {d.noteZh}
                  </span>
                </span>
              </li>
            ))}
          </ol>

          <p className="shan-guide__couplet">
            <Cadence
              text="一山一水，皆從墨中來。"
              lang="zh"
              step={140}
              start={400}
            />
          </p>
          <p className="shan-guide__couplet-en">
            <em>
              Every mountain, every river — arrives out of ink.
            </em>
          </p>
        </div>
      </div>
    </section>
  );
}

/**
 * Procedural shan-shui landscape generation — pure, deterministic, no React.
 *
 * The benchmark to surpass is `{Shan, Shui}*` by LingDong, which synthesizes
 * mountains, trees, mist and waterfalls from noise and draws them as SVG.
 * This module answers it for a live canvas: mountains built from multi-octave
 * value noise and drawn as filled silhouette paths whose ink density *is*
 * their depth (远山如黛 — "distant mountains are like eyebrow pigment"),
 * mist as soft radial-gradient blobs pooled in valleys, and recursive
 * brushstroke trees. Everything is seeded so the scroll is the same painting
 * on every visit, yet it generates forever in both directions.
 *
 * Used by the hero canvas (LandscapeCanvas.tsx) and safe to call at module
 * load on both server and client — the permutation is identical across
 * hydration, which is what lets the no-JS / SSR state already be a painting.
 */

/* --------------------------------------------------------------------------
   Determinism
   -------------------------------------------------------------------------- */

/** mulberry32 — tiny seeded PRNG; the landscape is the same painting every visit. */
export function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** 256-entry permutation for the lattice hash. Seeded 1368 — a Ming year. */
function buildPerm(seed: number): Uint8Array {
  const rand = mulberry32(seed);
  const p = new Uint8Array(256);
  for (let i = 0; i < 256; i++) p[i] = i;
  for (let i = 255; i > 0; i--) {
    const j = (rand() * (i + 1)) | 0;
    const t = p[i];
    p[i] = p[j];
    p[j] = t;
  }
  return p;
}

const PERM = buildPerm(1368);

/** Lattice hash → [0, 1). */
function latHash(ix: number, iy: number): number {
  return PERM[(ix + PERM[iy & 255]) & 255] / 255;
}

/** Smooth-stepped bilinear value noise over the integer lattice. */
export function valueNoise(x: number, y: number): number {
  const ix = Math.floor(x);
  const iy = Math.floor(y);
  let fx = x - ix;
  let fy = y - iy;
  fx = fx * fx * (3 - 2 * fx);
  fy = fy * fy * (3 - 2 * fy);
  const a = latHash(ix, iy);
  const b = latHash(ix + 1, iy);
  const c = latHash(ix, iy + 1);
  const d = latHash(ix + 1, iy + 1);
  return a + (b - a) * fx + (c - a) * fy + (a - b - c + d) * fx * fy;
}

/** Clamp. */
export function clamp(v: number, lo: number, hi: number): number {
  return v < lo ? lo : v > hi ? hi : v;
}

/** Smoothstep — Hermite interpolation. */
export function smoothstep(a: number, b: number, x: number): number {
  const s = clamp((x - a) / (b - a), 0, 1);
  return s * s * (3 - 2 * s);
}

/* --------------------------------------------------------------------------
   Mountain ridge generation
   -------------------------------------------------------------------------- */

/**
 * A ridge layer in the depth stack. Far layers are paler, smaller, and ride
 * higher (closer to the horizon); near layers are darker, taller, and ride
 * lower. The ink density IS the aerial perspective.
 */
export type RidgeLayer = {
  /** 0 = farthest, RIDGE_LAYERS-1 = nearest. */
  depth: number;
  /** Base horizon y as a fraction of stage height (top=0). Larger = lower. */
  baseY: number;
  /** Amplitude of the ridge as a fraction of stage height. */
  amp: number;
  /** Horizontal noise frequency (px⁻¹) — far ridges are broader. */
  freq: number;
  /** Per-layer phase offset so layers don't share peaks. */
  phase: number;
  /** Ink alpha — 远山如黛, distance is ink density. */
  ink: number;
  /** Ink color (rgb triple) for this layer — palest at the horizon. */
  rgb: [number, number, number];
};

/**
 * Five mountain layers, farthest first. Each nearer layer is darker, taller,
 * and sits lower on the paper — the canonical shan-shui depth structure.
 * Ink alphas and colors come from the design tokens (aerial-density motion).
 */
export const RIDGE_LAYERS: RidgeLayer[] = [
  // farthest — dissolving into mist
  {
    depth: 0,
    baseY: 0.34,
    amp: 0.05,
    freq: 1 / 520,
    phase: 11.2,
    ink: 0.14,
    rgb: [154, 148, 136], // pale-wash
  },
  {
    depth: 1,
    baseY: 0.44,
    amp: 0.08,
    freq: 1 / 360,
    phase: 37.7,
    ink: 0.26,
    rgb: [125, 117, 106], // ink-soft
  },
  // middle
  {
    depth: 2,
    baseY: 0.55,
    amp: 0.12,
    freq: 1 / 240,
    phase: 4.4,
    ink: 0.42,
    rgb: [90, 82, 73], // ink-mid
  },
  // nearer
  {
    depth: 3,
    baseY: 0.68,
    amp: 0.16,
    freq: 1 / 170,
    phase: 71.3,
    ink: 0.62,
    rgb: [58, 52, 44], // ink-strong
  },
  // nearest — the foreground ridge, full ink
  {
    depth: 4,
    baseY: 0.82,
    amp: 0.2,
    freq: 1 / 120,
    phase: 92.8,
    ink: 0.82,
    rgb: [26, 23, 20], // sumi
  },
];

/** Octave amplitudes/weights for the ridge profile (roughness pyramid). */
const OCTAVE_FREQS = [1, 2.05, 4.4, 9.1];
const OCTAVE_WEIGHTS = [1, 0.52, 0.27, 0.13];

/**
 * The mountain silhouette height at world-x, for one ridge layer.
 * Sum of weighted value-noise bands — the canonical fBm ridge. `scrollX`
 * shifts the world so the same function paints an infinite scroll, and the
 * profile is deterministic for any x.
 */
export function ridgeHeight(
  layer: RidgeLayer,
  x: number,
  scrollX: number,
  stageH: number,
): number {
  const wx = (x + scrollX) * layer.freq + layer.phase;
  let h = 0;
  let wSum = 0;
  for (let o = 0; o < OCTAVE_FREQS.length; o++) {
    const f = OCTAVE_FREQS[o];
    h += (valueNoise(wx * f, layer.phase * f) - 0.5) * OCTAVE_WEIGHTS[o];
    wSum += OCTAVE_WEIGHTS[o];
  }
  h /= wSum; // normalize to ~[-0.5, 0.5]
  // ridges: sharpen peaks by reflecting the noise around 0.5 — mountain
  // silhouettes have pointed peaks and rounded valleys, unlike raw fBm.
  const ridge = 0.5 - Math.abs(h);
  const base = layer.baseY * stageH;
  const amp = layer.amp * stageH;
  return base - ridge * amp * 2.2;
}

/* --------------------------------------------------------------------------
   Trees — recursive brushstroke clusters
   -------------------------------------------------------------------------- */

export type TreeBranch = {
  /** Stroke points as flat [x0,y0,x1,y1,...] in stage-local px. */
  pts: number[];
  /** Stroke width in px. */
  w: number;
};

/**
 * A small recursive brushstroke tree (pine-like, the foreground accent of
 * literati painting). Grown deterministically from a seed; the turtle carries
 * a wander + slight upward phototropism so nothing alive is straight. Drawn
 * as a branching stroke cluster, not a literal pine silhouette — the brush
 * suggests the tree rather than describing it.
 */
export function growTree(
  seed: number,
  ox: number,
  oy: number,
  scale: number,
): TreeBranch[] {
  const rnd = mulberry32(seed);
  const branches: TreeBranch[] = [];
  type Frame = { x: number; y: number; ang: number; depth: number; pts: number[] };
  const stack: Frame[] = [];
  const stepLen = 26 * scale;
  let f: Frame = { x: ox, y: oy, ang: -90, depth: 0, pts: [ox, oy] };

  const pushBranch = (fr: Frame) => {
    if (fr.pts.length >= 4) {
      branches.push({ pts: fr.pts, w: Math.max(0.8, 4.6 * Math.pow(0.62, fr.depth) * scale) });
    }
  };

  // ~6 branching events from the trunk — a spare literati tree, not a bush.
  for (let i = 0; i < 38; i++) {
    if (f.depth > 4) {
      const p = stack.pop();
      if (p) {
        pushBranch(f);
        f = p;
      } else break;
      continue;
    }
    // wander + phototropism
    f.ang += (rnd() - 0.5) * 12;
    f.ang += (-90 - f.ang) * 0.04;
    const r = (f.ang * Math.PI) / 180;
    const len = stepLen * Math.pow(0.82, f.depth) * (0.8 + rnd() * 0.4);
    f.x += Math.cos(r) * len;
    f.y += Math.sin(r) * len;
    f.pts.push(f.x, f.y);
    // branch decision
    const roll = rnd();
    if (roll < 0.4) {
      // branch left
      stack.push({ ...f, pts: [f.x, f.y] });
      f.ang -= 26 + rnd() * 12;
      f.depth += 1;
      f.pts = [f.x, f.y];
    } else if (roll < 0.8) {
      // branch right
      stack.push({ ...f, pts: [f.x, f.y] });
      f.ang += 26 + rnd() * 12;
      f.depth += 1;
      f.pts = [f.x, f.y];
    }
    // else continue the current limb
  }
  pushBranch(f);
  return branches;
}

/* --------------------------------------------------------------------------
   Seasons — the atmospheric shift
   -------------------------------------------------------------------------- */

export type Season = "spring" | "summer" | "autumn" | "winter";

/**
 * The four atmospheric moods. The scroll cycles through them so the painting
 * is never quite the same weather twice — TAWARAYA's "12 months captured,"
 * distilled to four ink densities. The shift is slow and rides the deep
 * scroll position, never a sudden cut.
 */
export const SEASONS: Record<
  Season,
  {
    /** Display label (zh). */
    zh: string;
    /** Display label (en). */
    en: string;
    /** Mist density multiplier — winter is drowned in cloud. */
    mist: number;
    /** Far-ridge ink multiplier — winter recedes further into haze. */
    farFade: number;
    /** A faint tonal wash applied over the sky region (rgb + alpha). */
    wash: [number, number, number, number];
    /** A seasonal accent that appears rarely (plum-blossom dots in spring, etc). */
    accent: "plum" | "none" | "maple" | "snow";
  }
> = {
  spring: {
    zh: "春",
    en: "spring",
    mist: 0.9,
    farFade: 1.0,
    wash: [168, 50, 50, 0.012],
    accent: "plum",
  },
  summer: {
    zh: "夏",
    en: "summer",
    mist: 0.7,
    farFade: 1.0,
    wash: [58, 82, 58, 0.02],
    accent: "none",
  },
  autumn: {
    zh: "秋",
    en: "autumn",
    mist: 0.85,
    farFade: 0.92,
    wash: [150, 88, 44, 0.02],
    accent: "maple",
  },
  winter: {
    zh: "冬",
    en: "winter",
    mist: 1.35,
    farFade: 0.62,
    wash: [220, 220, 224, 0.05],
    accent: "snow",
  },
};

/** Ordered cycle, for indexing by scroll position. */
export const SEASON_ORDER: Season[] = ["spring", "summer", "autumn", "winter"];

/**
 * Blend two adjacent seasons by a 0..1 factor. The result is a smooth
 * atmospheric crossfade — the weather changes the way weather does.
 */
export function blendSeasons(
  a: Season,
  b: Season,
  t: number,
): { mist: number; farFade: number; wash: [number, number, number, number]; accent: Season } {
  const sa = SEASONS[a];
  const sb = SEASONS[b];
  const mist = sa.mist + (sb.mist - sa.mist) * t;
  const farFade = sa.farFade + (sb.farFade - sa.farFade) * t;
  const wash: [number, number, number, number] = [
    sa.wash[0] + (sb.wash[0] - sa.wash[0]) * t,
    sa.wash[1] + (sb.wash[1] - sa.wash[1]) * t,
    sa.wash[2] + (sb.wash[2] - sa.wash[2]) * t,
    sa.wash[3] + (sb.wash[3] - sa.wash[3]) * t,
  ];
  return { mist, farFade, wash, accent: t < 0.5 ? a : b };
}

"use client";

import { useEffect, useRef } from "react";

export type PointerSample = {
  /** Pointer x in stage-local CSS px (set when a hand is present). */
  x: number;
  /** Pointer y in stage-local CSS px. */
  y: number;
  /** Presence energy 0..1 — the canvas lerps this with attack/release. */
  e: number;
  /** performance.now() of the last pointermove. */
  t: number;
};

/**
 * Tracks a fine pointer (mouse/pen) into a ref, never re-rendering React.
 *
 * The canvas reads `target` each frame and lerps its own `ptr` toward it with
 * the asymmetric attack/release in tokens.json (pointer-breath): the painting
 * notices a hand within a quarter-second and takes a few seconds to forget it.
 * Touch is deliberately ignored — the mist self-drifts on touch devices so
 * nothing meaningful lives behind a hover. When the hand goes quiet (or never
 * existed) the canvas's autonomous breeze takes back over.
 *
 * `stageRef` is attached to the landscape stage; coordinates are reported
 * stage-local so the canvas needs no further translation.
 */
export function usePointerMist<T extends HTMLElement>() {
  const stageRef = useRef<T | null>(null);
  const target = useRef<PointerSample>({ x: 0, y: 0, e: 0, t: -1e9 });

  useEffect(() => {
    const stage = stageRef.current;
    if (!stage) return;
    const fine = window.matchMedia(
      "(hover: hover) and (pointer: fine)",
    ).matches;
    if (!fine) return;

    const onMove = (ev: PointerEvent) => {
      if (ev.pointerType !== "mouse" && ev.pointerType !== "pen") return;
      const rect = stage.getBoundingClientRect();
      const x = ev.clientX - rect.left;
      const y = ev.clientY - rect.top;
      if (x < -60 || x > rect.width + 60 || y < -60 || y > rect.height + 60)
        return;
      target.current = { x, y, e: 1, t: performance.now() };
    };

    stage.addEventListener("pointermove", onMove);
    return () => stage.removeEventListener("pointermove", onMove);
  }, []);

  return { stageRef, target };
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity/translate/
 * blur, or the couplet's per-glyph cadence) lives in styles.css and is gated
 * behind the `.shan-js` root class, so every word is plainly visible when
 * JavaScript never runs.
 *
 * Two flavors (matching the gallery convention):
 *   data-reveal          — the element itself fades and rises (0.9s), with a
 *                          90ms stagger between elements of the same batch.
 *   data-reveal="scene"  — the element does not animate itself; it only
 *                          receives `is-visible` so descendants (couplet
 *                          glyphs, captions) can run their own delays.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          if (el.dataset.reveal !== "scene") {
            el.style.transitionDelay = `${batch * 90}ms`;
            batch += 1;
          }
          el.classList.add("is-visible");
          io.unobserve(el);
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";

export type ScrollSample = {
  /** Raw scroll-y in CSS px. */
  y: number;
  /** Signed instantaneous velocity in px/ms (positive = down), clamped. */
  v: number;
  /** performance.now() timestamp of the last sample. */
  t: number;
};

/** Instantaneous velocity clamp — flicks beyond this read the same. */
const V_CLAMP = 6;

/**
 * Records scroll position and velocity into a ref, never re-rendering React.
 *
 * The hook is deliberately dumb: it samples raw `scrollY` + a clamped px/ms
 * velocity + its timestamp on every scroll event. Consumers (the landscape
 * canvas, the pinned layer parallax) read the ref inside their own rAF loops,
 * where smoothing and frame-rate normalization belong. A sample older than
 * ~140ms reads as "the scroll has stopped" — see LandscapeCanvas.
 */
export function useScrollProgress() {
  const sample = useRef<ScrollSample>({ y: 0, v: 0, t: 0 });

  useEffect(() => {
    let lastY = window.scrollY;
    let lastT = performance.now();
    sample.current = { y: lastY, v: 0, t: lastT };

    const onScroll = () => {
      const now = performance.now();
      const dt = now - lastT;
      const dy = window.scrollY - lastY;
      lastY = window.scrollY;
      lastT = now;
      if (dt <= 0) return;
      const v = dy / Math.max(dt, 4);
      sample.current = {
        y: window.scrollY,
        v: v > V_CLAMP ? V_CLAMP : v < -V_CLAMP ? -V_CLAMP : v,
        t: now,
      };
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    // Recalibrate on resize — scroll positions stay valid, but a layout
    // shift can land the viewport mid-section with no scroll firing.
    window.addEventListener("resize", onScroll, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onScroll);
    };
  }, []);

  return sample;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import "./styles.css";
import { cormorant, maShanZheng, notoSerifSC } from "./fonts";
import Loader from "./components/Loader";
import Hero from "./components/Hero";
import ScrollGuide from "./components/ScrollGuide";
import SealStamp from "./components/SealStamp";
import Footer from "./components/Footer";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";
import { useScrollProgress } from "./hooks/useScrollProgress";

/**
 * 山水 SHAN-SHUI — a procedurally-generated, infinitely-scrolling Chinese
 * ink-wash landscape that paints itself live in the browser. The scroll IS
 * the unrolling of a hand scroll (手卷): page-scroll drives a world-x offset
 * through layered value-noise mountains, and distance is expressed as ink
 * density (远山如黛), not perspective. Mist pools in the valleys and leans
 * toward a fine pointer, the weather slowly cycles through the four seasons,
 * and a vermillion seal marks the scroll. Everything on screen is code — the
 * mountains are canvas, the seal is SVG. No image would be still enough.
 *
 * `.shan-js` is added imperatively on mount (it never changes, so it is a
 * signal to CSS that JS is alive, not React state): every pre-reveal style
 * is gated behind it, and with JavaScript off the full page simply stands
 * finished — the SSR landscape backdrop is already a painting. The `entered`
 * state is React's, because the hero's cadence genuinely depends on the
 * loader lifting.
 */
export default function ShanShuiPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);
  const scrollRef = useScrollProgress();
  const [entered, setEntered] = useState(false);
  const handleEntered = useCallback(() => setEntered(true), []);

  useEffect(() => {
    rootRef.current?.classList.add("shan-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "shan-shui" }, "*");
  }, []);

  return (
    <div
      id="shan-top"
      ref={rootRef}
      className={`${cormorant.variable} ${maShanZheng.variable} ${notoSerifSC.variable} shan-root`}
    >
      <Loader onDone={handleEntered} />

      <div ref={revealRef} className="shan-sheet">
        <Hero entered={entered} scrollRef={scrollRef} />
        <main>
          <ScrollGuide />
          <SealStamp />
        </main>
        <Footer />
      </div>

      {/* Xuan grain: one static feTurbulence pass over everything.
          Rice-paper fibers, not film grain — it never animates. */}
      <svg className="shan-grain" aria-hidden="true" focusable="false">
        <filter id="shan-grain-f">
          <feTurbulence
            type="fractalNoise"
            baseFrequency="0.62"
            numOctaves="2"
            seed="8"
            stitchTiles="stitch"
          />
          <feColorMatrix
            type="matrix"
            values="0 0 0 0 0.102  0 0 0 0 0.09  0 0 0 0 0.078  0 0 0 0.05 0"
          />
        </filter>
        <rect width="100%" height="100%" filter="url(#shan-grain-f)" />
      </svg>
    </div>
  );
}

/* ==========================================================================
   山水 SHAN-SHUI — procedurally-generated ink landscape
   washi-sumi-e · xuan / sumi / pale-wash / vermillion chop · a hand-scroll
   Scoped by convention to .shan-root; classes prefixed shan-.
   ========================================================================== */

.shan-root {
  /* -- palette ----------------------------------------------------------- */
  --shan-xuan: #f4ede0;          /* the rice paper — every ridge is brushed on it */
  --shan-xuan-aged: #ece3d2;     /* older paper — guide panels, aged hems */
  --shan-sumi: #1a1714;          /* the ink stone, fully ground — 15.3:1 on xuan */
  --shan-ink-strong: #3a342c;    /* sumi + one dip of water — 10.6:1 */
  --shan-ink-mid: #5a5249;       /* sumi thinned — body prose, mid ridges — 6.6:1 */
  --shan-ink-soft: #7d756a;      /* a pale wash — captions, far ridges — 3.9:1, large only */
  --shan-pale-wash: #9a9488;     /* farthest ridges dissolving — 2.6:1, decorative only */
  --shan-mist: #b8b1a3;          /* the mist — paint, never text — 1.8:1 */
  --shan-vermillion: #a83232;    /* the artist's chop — 5.7:1 on xuan (large/non-text) */
  --shan-vermillion-deep: #8a2626; /* banked seal — functional accent — 7.6:1 */
  --shan-xuan-dim: rgba(244, 237, 224, 0.72); /* ≈ #cfc7b6 on sumi — 11.7:1 */
  --shan-hairline: rgba(26, 23, 20, 0.16);
  --shan-hairline-strong: rgba(26, 23, 20, 0.3);

  /* -- type ---------------------------------------------------------------- */
  --shan-font-latin: var(--font-cormorant), "Cormorant Garamond", serif;
  --shan-font-zh-display: var(--font-mashan), "Ma Shan Zheng", serif;
  --shan-font-zh-body: var(--font-notosc), "Noto Serif SC", serif;
  /* CJK falls through Cormorant into the brush face with no markup */
  --shan-font-stack: var(--font-cormorant), var(--font-mashan), var(--font-notosc), serif;

  /* -- motion ---------------------------------------------------------------
     Two easings: scroll (rises fast, settles long) for entrances, stone
     (deliberate, weighted) for the seal press and section pins. */
  --shan-ease-scroll: cubic-bezier(0.22, 1, 0.36, 1);
  --shan-ease-stone: cubic-bezier(0.65, 0, 0.35, 1);
  --shan-reveal-ms: 900ms;
  --shan-glyph-ms: 1100ms;
  --shan-loader-lift: 680ms;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--shan-xuan);
  color: var(--shan-sumi);
  font-family: var(--shan-font-stack);
  font-weight: 400;
  font-size: clamp(17px, 1vw + 12px, 20px);
  line-height: 1.75;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Chinese is first-class: the brush face for display, the mincho for body.
   Either way, the glyphs get a little room to breathe. */
.shan-root :lang(zh) {
  font-family: var(--shan-font-zh-body);
  letter-spacing: 0.04em;
}

/* Vermillion selection, scoped to the entry root. Banked seal ground so the
   selected xuan text stays AA (7.6:1). */
.shan-root ::selection {
  background: var(--shan-vermillion-deep);
  color: var(--shan-xuan);
  text-shadow: none;
}

/* Keyboard focus: a vermillion-deep ring, held one paper-thickness away. */
.shan-root :focus-visible {
  outline: 2px solid var(--shan-vermillion-deep);
  outline-offset: 4px;
  border-radius: 1px;
}

.shan-foot :focus-visible {
  outline-color: var(--shan-vermillion);
}

/* Visually hidden, present for screen readers and find-in-page. */
.shan-sr {
  position: absolute;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
  border: 0;
}

.shan-sheet {
  position: relative;
}

/* Glyphs cut into the seals — always the brush face, wherever the seal appears. */
.shan-sealglyph {
  font-family: var(--shan-font-zh-display);
}

/* ==========================================================================
   Xuan — the paper itself
   One static feTurbulence grain pass (multiplied, ≤5% ink) and a faint
   amber age-vignette at the edges. Neither ever animates; the paper is old.
   ========================================================================== */

.shan-grain {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: 40;
  pointer-events: none;
  mix-blend-mode: multiply;
  opacity: 0.7;
}

.shan-root::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 39;
  pointer-events: none;
  background:
    radial-gradient(
      120% 95% at 50% 42%,
      transparent 55%,
      rgba(168, 50, 50, 0.05) 100%
    ),
    repeating-linear-gradient(
      0deg,
      rgba(26, 23, 20, 0.014) 0 2px,
      transparent 2px 8px
    );
}

/* ==========================================================================
   Reveal primitives
   Everything pre-reveal lives under .shan-js: with JavaScript off the page
   stands finished. data-reveal elements fade-rise; data-reveal="scene"
   containers never move themselves — they only hand `is-visible` to the
   choreography inside.
   ========================================================================== */

.shan-js [data-reveal]:not([data-reveal="scene"]) {
  opacity: 0;
  transform: translateY(16px);
  transition:
    opacity var(--shan-reveal-ms) var(--shan-ease-scroll),
    transform var(--shan-reveal-ms) var(--shan-ease-scroll);
}

.shan-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* Split glyphs — the wordmark and the couplet share one cadence system.
   Each glyph carries its own delay as --kd; only opacity/transform/filter
   ever animate. */
.shan-hero__glyph,
.shan-cadence__g {
  display: inline-block;
  transition:
    opacity var(--shan-glyph-ms) var(--shan-ease-scroll) var(--kd, 0ms),
    transform var(--shan-glyph-ms) var(--shan-ease-scroll) var(--kd, 0ms),
    filter var(--shan-glyph-ms) var(--shan-ease-scroll) var(--kd, 0ms);
}

.shan-js .shan-hero:not(.is-entered) .shan-hero__glyph,
.shan-js .shan-hero:not(.is-entered) .shan-cadence__g,
.shan-js [data-reveal="scene"]:not(.is-visible) .shan-cadence__g {
  opacity: 0;
  transform: translateY(0.14em);
  filter: blur(4px);
  transition: none;
}

/* ==========================================================================
   Loader — the seal, then the paper lifts
   Rendered only after mount and never under reduced motion, so it can never
   hide content from anyone.
   ========================================================================== */

.shan-loader {
  position: fixed;
  inset: 0;
  z-index: 70;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--shan-xuan);
}

.shan-loader__seal {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 22px;
}

.shan-loader__seal svg {
  transform: rotate(-5deg);
  animation: shan-seal-press 720ms var(--shan-ease-stone) both;
}

@keyframes shan-seal-press {
  0% {
    opacity: 0;
    transform: scale(1.18) rotate(-1deg);
  }
  55% {
    opacity: 1;
    transform: scale(0.96) rotate(-5.5deg);
  }
  100% {
    opacity: 1;
    transform: scale(1) rotate(-5deg);
  }
}

.shan-loader__word {
  margin: 0;
  font-size: 0.78rem;
  letter-spacing: 0.34em;
  text-transform: uppercase;
  color: var(--shan-ink-mid);
  opacity: 0;
  animation: shan-fade 600ms var(--shan-ease-scroll) 380ms forwards;
}

.shan-loader__word :lang(zh) {
  text-transform: none;
  letter-spacing: 0.18em;
  margin-left: 0.6em;
}

@keyframes shan-fade {
  to {
    opacity: 1;
  }
}

.shan-loader.is-lifting {
  animation: shan-paper-lift var(--shan-loader-lift) var(--shan-ease-stone)
    forwards;
}

@keyframes shan-paper-lift {
  to {
    opacity: 0;
    transform: translateY(-2.5%);
  }
}

/* ==========================================================================
   Hero — the landscape, the wordmark
   Layers, bottom to top: landscape canvas (0) · text (1). The mountains
   stand behind the wordmark the way real mountains stand behind a colophon.
   ========================================================================== */

.shan-hero {
  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
}

.shan-landscape {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
}

/* The canvas accepts pointer events only on fine pointers (for mist pull);
   touch falls through to scroll. The hook only listens to mouse/pen anyway. */
@media (hover: hover) and (pointer: fine) {
  .shan-landscape {
    pointer-events: auto;
  }
}

.shan-landscape__canvas {
  display: block;
  width: 100%;
  height: 100%;
}

.shan-hero__inner {
  position: relative;
  z-index: 1;
  padding: clamp(24px, 6vw, 64px);
}

.shan-hero__kicker {
  margin: 0 0 2rem;
  font-size: 0.78rem;
  font-weight: 500;
  letter-spacing: 0.42em;
  text-transform: uppercase;
  color: var(--shan-vermillion-deep);
  text-shadow: 0 1px 0 var(--shan-xuan);
}

.shan-hero__kickerzh {
  display: inline-block;
  margin-left: 1em;
  text-transform: none;
  letter-spacing: 0.16em;
  font-family: var(--shan-font-zh-display);
}

.shan-hero__title {
  margin: 0;
  font-family: var(--shan-font-latin);
  font-weight: 500;
  font-size: clamp(3.4rem, 15vw, 11rem);
  line-height: 0.95;
  letter-spacing: 0.14em;
  text-indent: 0.14em; /* optically recenters the tracked line */
  color: var(--shan-sumi);
  text-shadow: 0 2px 0 var(--shan-xuan);
}

.shan-hero__sub {
  margin: 1.6rem 0 0;
  font-family: var(--shan-font-zh-display);
  font-size: clamp(1.6rem, 3.4vw, 2.6rem);
  letter-spacing: 0.18em;
  color: var(--shan-ink-strong);
  text-shadow: 0 1px 0 var(--shan-xuan);
}

.shan-hero__rule {
  width: 64px;
  height: 1px;
  margin: 2.4rem auto;
  background: var(--shan-vermillion);
  box-shadow: 0 0 0 1px rgba(244, 237, 224, 0.6);
}

.shan-hero__line {
  margin: 0;
  font-size: clamp(1rem, 1.6vw, 1.2rem);
  color: var(--shan-sumi);
  max-width: 38rem;
  margin-inline: auto;
  text-shadow: 0 1px 0 var(--shan-xuan);
}

.shan-hero__linezh {
  display: block;
  margin-top: 0.5rem;
  font-size: 0.95em;
  color: var(--shan-ink-mid);
  font-family: var(--shan-font-zh-body);
}

.shan-hero__est {
  margin: 2.2rem 0 0;
  font-size: 0.82rem;
  letter-spacing: 0.12em;
  color: var(--shan-ink-mid);
  text-shadow: 0 1px 0 var(--shan-xuan);
}

.shan-hero__est :lang(zh) {
  margin-left: 0.6em;
}

.shan-hero__hint {
  position: absolute;
  z-index: 1;
  left: 50%;
  bottom: 14px;
  transform: translateX(-50%);
  margin: 0;
  font-size: 0.72rem;
  letter-spacing: 0.3em;
  color: var(--shan-ink-mid);
  white-space: nowrap;
  animation: shan-hint-drift 11.3s ease-in-out infinite;
  text-shadow: 0 1px 0 var(--shan-xuan);
}

.shan-hero__hint :lang(zh) {
  margin-right: 0.8em;
  font-family: var(--shan-font-zh-display);
}

@keyframes shan-hint-drift {
  0%,
  100% {
    transform: translateX(-50%) translateY(0);
    opacity: 0.85;
  }
  50% {
    transform: translateX(-50%) translateY(5px);
    opacity: 0.55;
  }
}

/* ==========================================================================
   Section shell — eyebrow · title · line
   ========================================================================== */

.shan-guide,
.shan-seal {
  padding-block: clamp(96px, 15vh, 176px);
}

.shan-eyebrow {
  margin: 0 0 1.2rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.3em;
  color: var(--shan-vermillion-deep);
}

/* ==========================================================================
   02 — the scroll guide (scroll-scrub-pinned)
   A pinned stage whose parallax layers part with scroll progress. --p (0..1)
   is written by a scroll listener in ScrollGuide's mounting; without JS the
   layers rest at their composed resting positions.
   ========================================================================== */

.shan-guide__stage {
  position: relative;
  max-width: 1120px;
  margin-inline: auto;
  padding-inline: clamp(20px, 6vw, 72px);
  display: grid;
  grid-template-columns: 1fr;
  gap: clamp(48px, 7vw, 96px);
}

.shan-guide__art {
  position: relative;
  height: clamp(220px, 34vh, 360px);
  display: flex;
  align-items: center;
  justify-content: center;
  /* --p is driven by the scroll-scrub; defaults to a composed mid-state */
  --p: 0.5;
}

.shan-guide__layer {
  position: absolute;
  font-family: var(--shan-font-zh-display);
  line-height: 1;
  transition: transform 200ms var(--shan-ease-scroll);
}

.shan-guide__layer--far {
  font-size: clamp(7rem, 22vw, 16rem);
  color: var(--shan-pale-wash);
  transform: translateY(calc(-40px * var(--p))) scale(calc(1 - 0.06 * var(--p)));
  opacity: 0.55;
}
.shan-guide__layer--mid {
  font-size: clamp(6rem, 19vw, 14rem);
  color: var(--shan-ink-soft);
  transform: translateY(calc(-20px * var(--p))) translateX(calc(-30px * var(--p))) scale(calc(1 - 0.04 * var(--p)));
  opacity: 0.7;
}
.shan-guide__layer--near {
  font-size: clamp(5.5rem, 17vw, 13rem);
  color: var(--shan-ink-mid);
  transform: translateY(calc(8px * var(--p))) translateX(calc(40px * var(--p)));
  opacity: 0.85;
}
.shan-guide__layer--fg {
  font-size: clamp(5rem, 15vw, 12rem);
  color: var(--shan-sumi);
  transform: translateY(calc(30px * var(--p))) translateX(calc(-18px * var(--p)));
}

.shan-guide__copy {
  max-width: 44rem;
  margin-inline: auto;
  text-align: center;
}

.shan-guide__title {
  margin: 0;
  font-family: var(--shan-font-latin);
  font-weight: 400;
  font-size: clamp(2rem, 4.6vw, 3.2rem);
  line-height: 1.18;
  letter-spacing: 0.03em;
  color: var(--shan-sumi);
}

.shan-guide__titlezh {
  display: block;
  margin-top: 0.3em;
  font-family: var(--shan-font-zh-display);
  font-size: 0.7em;
  letter-spacing: 0.12em;
  color: var(--shan-vermillion-deep);
}

.shan-guide__lede {
  margin: 1.6rem 0 0;
  font-size: clamp(1.05rem, 1.5vw, 1.2rem);
  color: var(--shan-ink-mid);
}

.shan-guide__ledezh {
  display: block;
  margin-top: 0.6rem;
  font-family: var(--shan-font-zh-body);
  color: var(--shan-ink-strong);
}

.shan-guide__distances {
  list-style: none;
  margin: clamp(2.4rem, 5vh, 3.6rem) 0 0;
  padding: 0;
  text-align: left;
  counter-reset: dist;
}

.shan-guide__row {
  display: grid;
  grid-template-columns: auto auto 1fr;
  grid-template-areas:
    "zh py en"
    "note note note";
  gap: 0.3rem 1.2rem;
  align-items: baseline;
  padding-block: clamp(20px, 3vh, 32px);
  border-top: 1px solid var(--shan-hairline);
  opacity: 0;
  transform: translateY(14px);
  transition:
    opacity 800ms var(--shan-ease-scroll) var(--kd, 0ms),
    transform 800ms var(--shan-ease-scroll) var(--kd, 0ms);
}

.shan-js [data-reveal="scene"].is-visible .shan-guide__row {
  opacity: 1;
  transform: none;
}

.shan-guide__row:last-child {
  border-bottom: 1px solid var(--shan-hairline);
}

.shan-guide__zh {
  grid-area: zh;
  font-family: var(--shan-font-zh-display);
  font-size: clamp(1.8rem, 3vw, 2.4rem);
  color: var(--shan-vermillion-deep);
  line-height: 1;
}

.shan-guide__py {
  grid-area: py;
  font-style: italic;
  font-size: 0.9rem;
  color: var(--shan-ink-soft);
  letter-spacing: 0.04em;
}

.shan-guide__en {
  grid-area: en;
  font-family: var(--shan-font-latin);
  font-size: clamp(1.15rem, 1.8vw, 1.4rem);
  color: var(--shan-sumi);
}

.shan-guide__note {
  grid-area: note;
  margin-top: 0.3rem;
  font-size: 0.95rem;
  color: var(--shan-ink-mid);
}

.shan-guide__notezh {
  display: block;
  margin-top: 0.3rem;
  font-family: var(--shan-font-zh-body);
  color: var(--shan-ink-strong);
}

.shan-guide__couplet {
  margin: clamp(2.4rem, 5vh, 3.6rem) 0 0;
  font-family: var(--shan-font-zh-display);
  font-size: clamp(1.6rem, 3vw, 2.2rem);
  letter-spacing: 0.14em;
  color: var(--shan-sumi);
  line-height: 1.6;
}

.shan-guide__couplet-en {
  margin: 0.6rem 0 0;
  font-style: italic;
  font-size: clamp(1.05rem, 1.6vw, 1.25rem);
  color: var(--shan-ink-mid);
}

/* ==========================================================================
   03 — the seal stamp (the artist's chop)
   The one interactive flourish. A real button; the impression blooms on press.
   ========================================================================== */

.shan-seal__inner {
  max-width: 880px;
  margin-inline: auto;
  padding-inline: clamp(20px, 6vw, 72px);
  text-align: center;
}

.shan-seal__title {
  margin: 0;
  font-family: var(--shan-font-latin);
  font-weight: 400;
  font-size: clamp(1.9rem, 4.2vw, 2.9rem);
