  letter-spacing: 0.03em;
  color: var(--shan-sumi);
}

.shan-seal__titlezh {
  display: block;
  margin-top: 0.3em;
  font-family: var(--shan-font-zh-display);
  font-size: 0.7em;
  letter-spacing: 0.1em;
  color: var(--shan-vermillion-deep);
}

.shan-seal__line {
  max-width: 40rem;
  margin: 1.6rem auto 0;
  color: var(--shan-ink-mid);
}

.shan-seal__linezh {
  display: block;
  margin-top: 0.6rem;
  font-family: var(--shan-font-zh-body);
  color: var(--shan-ink-strong);
}

.shan-seal__stage {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: clamp(1.6rem, 3vh, 2.4rem);
  margin-top: clamp(2.4rem, 5vh, 3.6rem);
}

.shan-seal__paper {
  position: relative;
  width: 132px;
  height: 132px;
  background: var(--shan-xuan-aged);
  border: 1px solid var(--shan-hairline);
  box-shadow: 0 1px 0 rgba(26, 23, 20, 0.06);
  display: flex;
  align-items: center;
  justify-content: center;
}

/* The impression left behind — invisible until the first stamp, then a
   fresh one blooms each press (key={count} remounts it). */
.shan-seal__impression {
  width: 96px;
  height: 96px;
  transform: rotate(-4deg);
  opacity: 0;
}

.shan-seal__impression.is-stamped {
  animation: shan-impress 700ms var(--shan-ease-stone) forwards;
}

@keyframes shan-impress {
  0% {
    opacity: 0;
    transform: scale(1.18) rotate(-1deg);
  }
  55% {
    opacity: 0.95;
    transform: scale(0.96) rotate(-4.5deg);
  }
  100% {
    opacity: 0.92;
    transform: scale(1) rotate(-4deg);
  }
}

.shan-seal__btn {
  display: inline-flex;
  flex-direction: column;
  align-items: center;
  gap: 0.7rem;
  padding: 0;
  border: 0;
  background: none;
  cursor: pointer;
  color: var(--shan-sumi);
  font: inherit;
}

.shan-seal__btnface {
  display: block;
  transition: transform 200ms var(--shan-ease-stone);
}

.shan-seal__btn:hover .shan-seal__btnface,
.shan-seal__btn:focus-visible .shan-seal__btnface {
  transform: translateY(-4px);
}

.shan-seal__btn.is-pressing .shan-seal__btnface {
  animation: shan-chop 900ms var(--shan-ease-stone);
}

@keyframes shan-chop {
  0% {
    transform: translateY(-6px) rotate(2deg);
  }
  35% {
    transform: translateY(6px) scale(0.94) rotate(-4deg);
  }
  100% {
    transform: translateY(0) rotate(0deg);
  }
}

.shan-seal__btnlabel {
  font-size: 0.78rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: var(--shan-vermillion-deep);
}

.shan-seal__btnlabelzh {
  display: block;
  margin-top: 0.3em;
  text-transform: none;
  letter-spacing: 0.16em;
  font-family: var(--shan-font-zh-display);
  font-size: 1.1em;
}

.shan-seal__count {
  margin: clamp(1.6rem, 3vh, 2.4rem) 0 0;
  font-size: 0.9rem;
  font-style: italic;
  color: var(--shan-ink-mid);
}

.shan-seal__count :lang(zh) {
  display: block;
  margin-top: 0.3rem;
  font-style: normal;
  font-family: var(--shan-font-zh-body);
}

/* ==========================================================================
   04 — the colophon (the one inversion)
   The page inverts once: sumi ground, xuan voice. Vermillion is finally
   allowed to be loud — it clears AA on sumi.
   ========================================================================== */

.shan-foot {
  background: var(--shan-sumi);
  color: var(--shan-xuan);
  padding: clamp(110px, 18vh, 200px) clamp(20px, 6vw, 72px)
    clamp(48px, 7vh, 72px);
}

.shan-foot__inner {
  max-width: 880px;
  margin-inline: auto;
  text-align: center;
}

.shan-foot__eyebrow {
  margin: 0 0 1.4rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.3em;
  color: var(--shan-vermillion);
}

.shan-foot__title {
  margin: 0;
  font-family: var(--shan-font-latin);
  font-weight: 400;
  font-size: clamp(2.1rem, 5.4vw, 3.9rem);
  line-height: 1.2;
  letter-spacing: 0.03em;
}

.shan-foot__titlezh {
  display: block;
  margin-top: 0.4em;
  font-family: var(--shan-font-zh-display);
  font-size: 0.62em;
  letter-spacing: 0.12em;
  color: var(--shan-vermillion);
}

.shan-foot__line {
  max-width: 44rem;
  margin: 1.8rem auto 0;
  color: var(--shan-xuan-dim);
}

.shan-foot__linezh {
  display: block;
  margin-top: 0.6rem;
  font-family: var(--shan-font-zh-body);
  color: var(--shan-xuan);
}

.shan-foot__btn {
  position: relative;
  display: inline-block;
  margin-top: 3.2rem;
  padding: 1.05em 2.6em;
  border: 1px solid rgba(244, 237, 224, 0.4);
  color: var(--shan-xuan);
  text-decoration: none;
  font-size: 0.88rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  overflow: hidden;
}

/* The ink-fill: a scaleX pseudo-element, compositor-only. */
.shan-foot__btn::before {
  content: "";
  position: absolute;
  inset: 0;
  background: var(--shan-vermillion);
  transform: scaleX(0);
  transform-origin: left center;
  transition: transform 520ms var(--shan-ease-stone);
}

.shan-foot__btn:hover::before,
.shan-foot__btn:focus-visible::before {
  transform: scaleX(1);
}

.shan-foot__btntext {
  position: relative;
  transition: color 320ms var(--shan-ease-stone) 120ms;
}

.shan-foot__btn:hover .shan-foot__btntext,
.shan-foot__btn:focus-visible .shan-foot__btntext {
  color: var(--shan-xuan);
}

.shan-foot__btnzh {
  display: block;
  margin-top: 0.3em;
  font-family: var(--shan-font-zh-display);
  font-size: 1.05em;
  letter-spacing: 0.12em;
  text-transform: none;
}

.shan-foot__grid {
  max-width: 880px;
  margin: clamp(72px, 12vh, 120px) auto 0;
  border-top: 1px solid rgba(244, 237, 224, 0.18);
  padding-top: clamp(36px, 6vh, 56px);
  display: flex;
  flex-wrap: wrap;
  gap: 1.2rem 3rem;
  justify-content: space-between;
  align-items: baseline;
  text-align: left;
}

.shan-foot__grid p {
  margin: 0;
}

.shan-foot__brand {
  font-family: var(--shan-font-zh-display);
  font-size: 1.6rem;
  letter-spacing: 0.16em;
  color: var(--shan-xuan);
}

.shan-foot__branden {
  margin-left: 0.6em;
  font-family: var(--shan-font-latin);
  font-size: 0.7em;
  letter-spacing: 0.3em;
  color: var(--shan-xuan-dim);
}

.shan-foot__meta {
  font-size: 0.85rem;
  color: var(--shan-xuan-dim);
}

.shan-foot__meta :lang(zh) {
  display: block;
  margin-top: 0.3rem;
  font-family: var(--shan-font-zh-body);
}

.shan-foot__koan {
  margin: clamp(36px, 6vh, 56px) 0;
  text-align: center;
  font-style: italic;
  font-size: 0.95rem;
  color: var(--shan-xuan-dim);
}

.shan-foot__koanzh {
  display: block;
  margin-top: 0.4rem;
  font-style: normal;
  font-family: var(--shan-font-zh-body);
  color: var(--shan-xuan);
}

.shan-foot__base {
  border-top: 1px solid rgba(244, 237, 224, 0.12);
  padding-top: clamp(24px, 4vh, 36px);
}

.shan-foot__copy {
  margin: 0;
  font-size: 0.8rem;
  color: var(--shan-xuan-dim);
}

.shan-foot__copy :lang(zh) {
  margin-left: 0.4em;
  font-family: var(--shan-font-zh-body);
}

.shan-foot__dedication {
  margin: clamp(40px, 7vh, 64px) auto 0;
  max-width: 44rem;
  font-size: 0.82rem;
  line-height: 1.85;
  color: var(--shan-xuan-dim);
}

.shan-foot__dedication em {
  color: var(--shan-vermillion);
  font-style: italic;
}

/* ==========================================================================
   Composition at other widths
   ========================================================================== */

@media (max-width: 720px) {
  .shan-guide__row {
    grid-template-columns: auto 1fr;
    grid-template-areas:
      "zh en"
      "py py"
      "note note";
    row-gap: 0.4rem;
  }

  .shan-guide__py {
    font-size: 0.82rem;
  }

  .shan-foot__grid {
    flex-direction: column;
    align-items: flex-start;
  }

  .shan-hero__kickerzh {
    display: block;
    margin: 0.5em 0 0;
  }
}

/* ==========================================================================
   Reduced motion — the page as a finished painting
   The landscape paints one composed still (LandscapeCanvas), the loader
   never mounts (Loader), the parallax layers rest at their composed state,
   and CSS flattens every transition and ambient cycle.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .shan-loader {
    display: none;
  }

  .shan-hero__hint,
  .shan-loader__seal svg,
  .shan-loader__word {
    animation: none;
  }

  .shan-js [data-reveal]:not([data-reveal="scene"]),
  .shan-hero__glyph,
  .shan-cadence__g,
  .shan-guide__row,
  .shan-js .shan-hero:not(.is-entered) .shan-hero__glyph,
  .shan-js .shan-hero:not(.is-entered) .shan-cadence__g,
  .shan-js [data-reveal="scene"]:not(.is-visible) .shan-cadence__g {
    opacity: 1;
    transform: none;
    filter: none;
    transition: none;
  }

  .shan-foot__btn::before,
  .shan-foot__btntext,
  .shan-seal__btnface,
  .shan-guide__layer {
    transition: none;
  }

  .shan-guide__art {
    --p: 0.5;
  }
}
